```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        auto result = sqlgen::result<void, sqlgen::Error>{};
        for (const auto& record : records) {
          result = sqlgen::insert(conn, record);
          if (!result) break;
        }
        return result;
      })
      .value();
}

template<typename ValueType>
void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const ValueType& new_value) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        // Determine primary key column name based on table
        std::string pk_col;
        if (table_name == "Student") pk_col = "SNo";
        else if (table_name == "Course") pk_col = "CID";
        else if (table_name == "Score") pk_col = "ScID";
        else if (table_name == "Major") pk_col = "MID";

        // Build and execute UPDATE query
        std::string sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_col + " = ?";
        return sqlgen::exec(conn, sql, new_value, record_id);
      })
      .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        // Determine primary key column name based on table
        std::string pk_col;
        if (table_name == "Student") pk_col = "SNo";
        else if (table_name == "Course") pk_col = "CID";
        else if (table_name == "Score") pk_col = "ScID";
        else if (table_name == "Major") pk_col = "MID";

        // Build and execute DELETE query
        std::string sql = "DELETE FROM " + table_name + " WHERE " + pk_col + " = ?";
        return sqlgen::exec(conn, sql, record_id);
      })
      .value();
}
```

This implementation:

1. **`add_eas_records`**: Template function that accepts a vector of records of any type `T`. It connects to the database and iterates through each record, inserting them one by one using `sqlgen::insert`.

2. **`modify_eas_records_by_id`**: Template function that accepts a value of any type `ValueType`. It determines the primary key column name based on the table name, then executes a parameterized UPDATE query using `sqlgen::exec`.

3. **`delete_eas_records_by_id`**: Determines the primary key column name based on the table name, then executes a parameterized DELETE query to remove the record with the specified ID.

All functions use the `and_then` monadic pattern for error handling and call `.value()` at the end to unwrap the result.

