#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_customer_purchase_history {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
  std::string email;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  sqlgen::ForeignKey<int, Customer, "customer_id"> customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  double total_amount;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  sqlgen::ForeignKey<int, Order, "order_id"> order_id;
  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};


/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  // 1. Connect to SQLite database
  auto db = sqlgen::sqlite::open("test_db.sqlite");

  // 2. Create tables
  db.create_table<Customer>();
  db.create_table<Product>();
  db.create_table<Order>();
  db.create_table<OrderItem>();

  // 3. Query the database to retrieve all products purchased by the customer
  // Using the reference SQL with proper column aliasing for PurchaseHistory mapping
  auto results = db.query<PurchaseHistory>(
    R"(SELECT p.name as product_name, o.order_date, oi.quantity
       FROM Customer c
       JOIN "Order" o ON c.customer_id = o.customer_id
       JOIN OrderItem oi ON o.order_id = oi.order_id
       JOIN Product p ON oi.product_id = p.product_id
       WHERE c.customer_id = ?
       ORDER BY o.order_date DESC)",
    customer_id
  );

  // 4. Return the results as a vector of PurchaseHistory
  return results;
}

}  // namespace query_customer_purchase_history

