    std::vector<EmployeeManager> results;

    for (auto&& row : query.execute()) {
        EmployeeManager em;
        // First column: employee name (always present)
        em.employee = std::get<0>(row);
        // Second column: manager name (optional - NULL for top-level employees)
        em.manager = std::get<1>(row);
        results.push_back(em);
    }

    return results;
}

