struct BookSearchResults {
  static constexpr const char* tablename = "BookSearchResults";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
