 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  sqlgen::sqlite::Database db("test_db.sqlite");

  auto customers = db.table<Customer>("Customer");
  auto orders = db.table<Order>("Order");
  auto payments = db.table<Payment>("Payment");

  auto query = db.select(
    orders.order_id,
    customers.name.as("customer_name"),
    payments.amount
  )
  .from(orders)
  .inner_join(customers).on(orders.customer_id == customers.customer_id)
  .inner_join(payments).on(orders.order_id == payments.order_id)
  .order_by(payments.amount.desc())
  .execute();

  std::vector<Consolidated> results;
  for (const auto& row : query) {
