```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool - true if cascade delete works correctly, false otherwise.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Enable foreign key constraints in SQLite (disabled by default)
  db.execute("PRAGMA foreign_keys = ON");

  // Drop existing tables to ensure clean state
  db.execute("DROP TABLE IF EXISTS Child");
  db.execute("DROP TABLE IF EXISTS Parent");

  // Create Parent table
  db.create_table<Parent>("Parent");

  // Create Child table with ON DELETE CASCADE constraint
  db.create_table<Child>("Child");

  // Insert parent records
  Parent parent1;
  parent1.parent_id = 1;
  parent1.name = "Parent 1";

  Parent parent2;
  parent2.parent_id = 2;
  parent2.name = "Parent 2";

  db.insert("Parent", parent1);
  db.insert("Parent", parent2);

  // Insert child records associated with parent_id = 1
  Child child1;
  child1.child_id = 1;
  child1.parent_id = 1;
  child1.note = "Child 1 of Parent 1";

  Child child2;
  child2.child_id = 2;
  child2.parent_id = 1;
  child2.note = "Child 2 of Parent 1";

  Child child3;
  child3.child_id = 3;
  child3.parent_id = 2;
  child3.note = "Child 1 of Parent 2";

  db.insert("Child", child1);
  db.insert("Child", child2);
  db.insert("Child", child3);

  // Delete parent record with parent_id = 1
  db.execute("DELETE FROM Parent WHERE parent_id = 1");

  // Verify that child records with parent_id = 1 are automatically deleted
  auto result = db.query("SELECT COUNT(*) as count FROM Child WHERE parent_id = 1");
  int count_deleted = result.get<int>("count");

  // Verify that child record with parent_id = 2 still exists
  auto result2 = db.query("SELECT COUNT(*) as count FROM Child WHERE parent_id = 2");
  int count_remaining = result2.get<int>("count");

  // Return true if cascade delete worked correctly:
  // - No children with parent_id = 1 (should be deleted)
  // - One child with parent_id = 2 (should remain)
  return (count_deleted == 0) && (count_remaining == 1);
}

}  // namespace cascade_delete_demo
