std::vector<SupProd> full_join_suppliers_products() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::Connection("test_db.sqlite");

  std::vector<SupProd> results;

  // SQLite doesn't natively support FULL OUTER JOIN, so we simulate it
  // by combining a LEFT JOIN with a query for unmatched products
  std::string query = 
    "SELECT s.name as supplier_name, p.name as product_name "
    "FROM Supplier s "
    "LEFT JOIN Product p ON s.supplier_id = p.supplier_id "
    "UNION "
    "SELECT COALESCE(s.name, '') as supplier_name, p.name as product_name "
    "FROM Product p "
    "LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id "
    "WHERE s.supplier_id IS NULL";

  // Execute the query
  auto result = db.execute(query);

  // Process each row
  for (const auto& row : result) {
    SupProd sp;
    sp.supplier_name = row.get<std::string>("supplier_name");

    // Check if product_name is NULL
    if (!row.is_null("product_name")) {
      sp.product_name = row.get<std::string>("product_name");
    } else {
      sp.product_name = std::nullopt;
    }

    results.push_back(sp);
  }

  return results;
}

