  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Create SQLite database connection
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Drop existing tables if they exist
  conn.execute("DROP TABLE IF EXISTS Employee");
  conn.execute("DROP TABLE IF EXISTS Department");

  // Create Department table
  conn.execute(R"(
    CREATE TABLE Department (
      department_id INTEGER PRIMARY KEY,
      department_name VARCHAR(100) NOT NULL,
      location VARCHAR(100)
    )
  )");

  // Create Employee table
  conn.execute(R"(
    CREATE TABLE Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name VARCHAR(50) NOT NULL,
      last_name VARCHAR(50) NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // Insert departments
  for (const auto& dept : depts) {
    auto stmt = conn.prepare(
      "INSERT INTO Department (department_id, department_name, location) VALUES (?, ?, ?)"
    );
    stmt.bind(1, dept.department_id.value);
    stmt.bind(2, dept.department_name);
    stmt.bind(3, dept.location);
    stmt.execute();
  }

  // Insert employees
  for (const auto& emp : emps) {
    auto stmt = conn.prepare(
      "INSERT INTO Employee (employee_id, department_id, first_name, last_name, salary) VALUES (?, ?, ?, ?, ?)"
    );
    stmt.bind(1, emp.employee_id.value);
    stmt.bind(2, emp.department_id);
    stmt.bind(3, emp.first_name);
    stmt.bind(4, emp.last_name);
    stmt.bind(5, emp.salary);
    stmt.execute();
  }

  JoinAnalysis analysis;

  // INNER JOIN - employees with assigned departments
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      INNER JOIN Employee e ON d.department_id = e.department_id
    )");

    auto result = stmt.execute();
    while (result.next()) {
      JoinResult jr;
      jr.department_name = result.get<std::string>(0);
      jr.first_name = result.get<std::string>(1);
      jr.last_name = result.get<std::string>(2);
      jr.salary = result.get<double>(3);
      analysis.inner_join_results.push_back(jr);
    }
  }

  // LEFT JOIN - all employees (even without departments)
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
    )");

    auto result = stmt.execute();
    while (result.next()) {
      JoinResult jr;
      if (!result.is_null(0)) {
        jr.department_name = result.get<std::string>(0);
      }
      if (!result.is_null(1)) {
        jr.first_name = result.get<std::string>(1);
      }
      if (!result.is_null(2)) {
        jr.last_name = result.get<std::string>(2);
      }
      if (!result.is_null(3)) {
        jr.salary = result.get<double>(3);
      }
      analysis.left_join_results.push_back(jr);
    }
  }

  // RIGHT JOIN - all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, so emulate with LEFT JOIN
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
    )");

    auto result = stmt.execute();
    while (result.next()) {
      JoinResult jr;
      if (!result.is_null(0)) {
        jr.department_name = result.get<std::string>(0);
      }
      if (!result.is_null(1)) {
        jr.first_name = result.get<std::string>(1);
      }
      if (!result.is_null(2)) {
        jr.last_name = result.get<std::string>(2);
      }
      if (!result.is_null(3)) {
        jr.salary = result.get<double>(3);
      }
      analysis.right_join_results.push_back(jr);
    }
  }

  // FULL JOIN - all employees and all departments
  // SQLite doesn't support FULL JOIN, so emulate with UNION
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
      UNION
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
      WHERE e.employee_id IS NULL
    )");

    auto result = stmt.execute();
    while (result.next()) {
      JoinResult jr;
      if (!result.is_null(0)) {
        jr.department_name = result.get<std::string>(0);
      }
      if (!result.is_null(1)) {
        jr.first_name = result.get<std::string>(1);
      }
      if (!result.is_null(2)) {
        jr.last_name = result.get<std::string>(2);
      }
      if (!result.is_null(3)) {
        jr.salary = result.get<double>(3);
      }
      analysis.full_join_results.push_back(jr);
    }
  }

  return analysis;
}

}  // namespace analyze_department_employees

