inline auto create_table_as_select() {
    // Create a table reference for Source
    auto source = sqlgen::table<Source>("Source");

    // Construct CREATE TABLE Target AS SELECT query
    // Select value from Source where value > 100
    auto query = sqlgen::create_table("Target").as(
        sqlgen::select(source.value)
